function f(o,e){const a=new Set,p=o.split(",").map(s=>s.trim()).filter(Boolean);for(const s of p)if(s.includes("-")){const[t,c]=s.split("-"),n=parseInt(t.trim(),10),i=parseInt(c.trim(),10);if(!isNaN(n)&&!isNaN(i))for(let r=Math.max(1,n);r<=Math.min(e,i);r++)a.add(r-1)}else{const t=parseInt(s,10);!isNaN(t)&&t>=1&&t<=e&&a.add(t-1)}return Array.from(a).sort((s,t)=>s-t)}export{f as p};
